import{_ as d,C as u,o as i,c as h,a2 as o,b as r,w as a,a as t,E as s,a3 as n,j as c}from"./chunks/framework.Bj6f68Cg.js";const B=JSON.parse('{"title":"GoVail Gateway","description":"","frontmatter":{},"headers":[],"relativePath":"projects/govail-gateway.md","filePath":"projects/govail-gateway.md"}'),p={name:"projects/govail-gateway.md"};function A(y,e,m,g,P,E){const l=u("Mermaid");return i(),h("div",null,[e[2]||(e[2]=o('<h1 id="govail-gateway" tabindex="-1">GoVail Gateway <a class="header-anchor" href="#govail-gateway" aria-label="Permalink to &quot;GoVail Gateway&quot;">​</a></h1><p>외부 AI 요청을 인증·정책·감사 경계에서 통제하고 사설 LLM 라우터로 전달하는 Rust 기반 OpenAI-compatible Gateway입니다.</p><h2 id="📌-status-repository" tabindex="-1">📌 Status &amp; Repository <a class="header-anchor" href="#📌-status-repository" aria-label="Permalink to &quot;📌 Status &amp; Repository&quot;">​</a></h2><ul><li><strong>상태</strong>: <code>MVP · Live Demo</code></li><li><strong>저장소 공개 범위</strong>: 비공개 구현 저장소</li><li><strong>직접 체험</strong>: <a href="/live-demo">Portfolio Live LLM</a></li><li><strong>주요 언어</strong>: Rust</li></ul><hr><h2 id="_1-problem" tabindex="-1">1. Problem <a class="header-anchor" href="#_1-problem" aria-label="Permalink to &quot;1. Problem&quot;">​</a></h2><p>LLM Client가 추론 Backend를 직접 호출하면 API Key 인증, 프로젝트별 모델 권한, 사용량 제한, DLP, Prompt Injection 차단과 감사 추적이 각 애플리케이션에 흩어집니다. 이 구조는 정책 일관성을 깨뜨리고, 사고가 발생했을 때 어떤 요청이 어느 모델 경로로 전달됐는지 재현하기 어렵게 만듭니다.</p><h2 id="_2-why-i-built-it" tabindex="-1">2. Why I Built It <a class="header-anchor" href="#_2-why-i-built-it" aria-label="Permalink to &quot;2. Why I Built It&quot;">​</a></h2><p>Provider와 모델이 바뀌어도 Client 계약을 유지하면서, AI 요청에 필요한 보안과 운영 정책을 하나의 Policy Enforcement Point에서 적용할 수 있는지 검증하기 위해 만들었습니다. 포트폴리오의 Live Demo도 별도 우회 경로가 아니라 이 Gateway의 실제 인증·감사 경계를 통과합니다.</p><h2 id="_3-scope" tabindex="-1">3. Scope <a class="header-anchor" href="#_3-scope" aria-label="Permalink to &quot;3. Scope&quot;">​</a></h2><ul><li>OpenAI-compatible Models, Chat Completions, Responses, Embeddings API</li><li>SurrealDB API Key Hash 조회와 프로젝트별 Principal 구성</li><li>JWT 서명·만료·블랙리스트 검증</li><li>프로젝트·Key별 Sliding Window RPM 제한</li><li>허용 모델, 기능 Capability와 요청 Parameter 정책</li><li>PII·Secret·Prompt Injection 탐지 및 차단</li><li>LiteLLM Upstream Retry와 Fallback 연결</li><li>Prometheus Metric, 구조화 Audit, Trace ID 전파</li></ul><h2 id="_4-architecture" tabindex="-1">4. Architecture <a class="header-anchor" href="#_4-architecture" aria-label="Permalink to &quot;4. Architecture&quot;">​</a></h2>',12)),(i(),r(n,null,{default:a(()=>[s(l,{id:"mermaid-92",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20Client%5B%22Web%20%C2%B7%20SDK%20%C2%B7%20Agent%22%5D%20--%3E%20Edge%5B%22Public%20API%20Gateway%22%5D%0A%20%20%20%20Edge%20--%3E%20GoVail%5B%22GoVail%20Gateway%22%5D%0A%20%20%20%20GoVail%20--%3E%20Auth%5B%22SurrealDB%20Auth%22%5D%0A%20%20%20%20Auth%20--%3E%20Policy%5B%22RPM%20%C2%B7%20Model%20%C2%B7%20DLP%22%5D%0A%20%20%20%20Policy%20--%3E%20Router%5B%22LiteLLM%20Router%22%5D%0A%20%20%20%20Router%20--%3E%20Primary%5B%22Primary%20Private%20LLM%22%5D%0A%20%20%20%20Router%20-.%20%22Fallback%22%20.-%3E%20Secondary%5B%22Secondary%20Private%20LLM%22%5D%0A%20%20%20%20GoVail%20--%3E%20Metrics%5B%22Prometheus%22%5D%0A%20%20%20%20GoVail%20--%3E%20Audit%5B%22Audit%20%C2%B7%20Loki%22%5D%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[t(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=c("h2",{id:"_5-request-flow",tabindex:"-1"},[t("5. Request Flow "),c("a",{class:"header-anchor",href:"#_5-request-flow","aria-label":'Permalink to "5. Request Flow"'},"​")],-1)),(i(),r(n,null,{default:a(()=>[s(l,{id:"mermaid-96",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20autonumber%0A%20%20%20%20participant%20Client%0A%20%20%20%20participant%20Gateway%20as%20GoVail%20Gateway%0A%20%20%20%20participant%20DB%20as%20SurrealDB%0A%20%20%20%20participant%20Router%20as%20LiteLLM%0A%20%20%20%20participant%20LLM%20as%20Private%20LLM%0A%20%20%20%20Client-%3E%3EGateway%3A%20Chat%20request%20%2B%20Bearer%20Key%0A%20%20%20%20Gateway-%3E%3EDB%3A%20Key%20Hash%EB%A1%9C%20Principal%20%EC%A1%B0%ED%9A%8C%0A%20%20%20%20DB--%3E%3EGateway%3A%20Project%2C%20Role%2C%20RPM%2C%20Allowed%20Models%0A%20%20%20%20Gateway-%3E%3EGateway%3A%20Rate%20Limit%2C%20Model%20Policy%2C%20DLP%20%EA%B2%80%EC%82%AC%0A%20%20%20%20alt%20%EC%A0%95%EC%B1%85%20%EC%9C%84%EB%B0%98%0A%20%20%20%20%20%20%20%20Gateway--%3E%3EClient%3A%204xx%20%2B%20Trace%20ID%0A%20%20%20%20else%20%EC%A0%95%EC%B1%85%20%ED%86%B5%EA%B3%BC%0A%20%20%20%20%20%20%20%20Gateway-%3E%3ERouter%3A%20%EC%A0%95%EA%B7%9C%ED%99%94%EB%90%9C%20OpenAI%20request%0A%20%20%20%20%20%20%20%20Router-%3E%3ELLM%3A%20Alias%20%EA%B8%B0%EB%B0%98%20%EB%AA%A8%EB%8D%B8%20%EB%9D%BC%EC%9A%B0%ED%8C%85%0A%20%20%20%20%20%20%20%20LLM--%3E%3ERouter%3A%20Completion%0A%20%20%20%20%20%20%20%20Router--%3E%3EGateway%3A%20Unified%20response%0A%20%20%20%20%20%20%20%20Gateway--%3E%3EClient%3A%20Response%20%2B%20Trace%20ID%0A%20%20%20%20end%0A%20%20%20%20Gateway-%3E%3EGateway%3A%20Metric%EA%B3%BC%20Audit%20Event%20%EA%B8%B0%EB%A1%9D%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[t(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=o(`<h2 id="_6-key-design-decisions" tabindex="-1">6. Key Design Decisions <a class="header-anchor" href="#_6-key-design-decisions" aria-label="Permalink to &quot;6. Key Design Decisions&quot;">​</a></h2><div class="decision-callout"><strong>Gateway는 정책, LiteLLM은 Provider Routing</strong><br> 인증·인가·DLP·감사는 GoVail이 소유하고 Provider Adapter, Retry와 모델 Fallback은 LiteLLM에 맡겨 책임 중복을 피했습니다. </div><ul><li>API Key 원문 대신 SHA-256 단축 Hash로 SurrealDB 레코드를 조회합니다.</li><li><code>project</code>, <code>role</code>, <code>rpm</code>, <code>allowed_models</code>를 인증 결과인 Principal에 묶어 이후 정책의 단일 기준으로 사용합니다.</li><li>Client는 실제 Model ID 대신 <code>auto</code> 같은 안정적인 Alias를 사용합니다.</li><li>요청마다 Trace ID를 부여해 Client 오류, Gateway Audit과 Upstream 장애를 연결합니다.</li></ul><h2 id="_7-security-considerations" tabindex="-1">7. Security Considerations <a class="header-anchor" href="#_7-security-considerations" aria-label="Permalink to &quot;7. Security Considerations&quot;">​</a></h2><div class="security-notice"> Live Demo Key는 공개 브라우저에서 보이는 전용 Token입니다. 운영 자격증명과 분리하고, <code>portfolio-demo</code> 프로젝트·<code>auto</code> 모델·낮은 RPM으로 권한을 제한합니다. </div><ul><li>인증 실패, 모델 권한 위반과 DLP 차단은 Upstream 전송 전에 종료합니다.</li><li>JWT는 만료와 <code>jti</code> 블랙리스트를 확인하며 프로젝트 Secret을 분리합니다.</li><li>감사 수집 단계에서 Key, Prompt와 Response를 제거하고 프로젝트·상태·지연 메타데이터만 Loki로 전달합니다.</li><li>현재 공개 Edge와 온프레미스 사이의 TLS Tunnel은 운영 전 필수 보완 항목입니다.</li></ul><h2 id="_8-observability" tabindex="-1">8. Observability <a class="header-anchor" href="#_8-observability" aria-label="Permalink to &quot;8. Observability&quot;">​</a></h2><ul><li><code>/metrics</code>에서 전체 요청, 정책 차단과 Upstream 오류 Counter를 제공합니다.</li><li>Prometheus가 Gateway를 직접 Scrape하고 Target Health를 감시합니다.</li><li>Promtail이 Audit JSONL에서 안전한 운영 필드만 추출해 Loki로 전달합니다.</li><li>Grafana <code>Portfolio Live LLM</code> 대시보드에서 체험 호출 수, 상태, 평균 지연과 최근 Trace를 확인합니다.</li><li><code>project=portfolio-demo</code> 필터로 다른 내부 Client와 공개 체험 트래픽을 분리합니다.</li></ul><h2 id="_9-technology-stack" tabindex="-1">9. Technology Stack <a class="header-anchor" href="#_9-technology-stack" aria-label="Permalink to &quot;9. Technology Stack&quot;">​</a></h2><ul><li><strong>Gateway</strong>: Rust, Axum, Tower HTTP</li><li><strong>Authentication</strong>: SurrealDB, JWT, SHA-256 Key Lookup</li><li><strong>Routing</strong>: LiteLLM, OpenAI-compatible API</li><li><strong>Observability</strong>: Prometheus, Promtail, Loki, Grafana</li><li><strong>Edge</strong>: GCP API Gateway</li><li><strong>Runtime</strong>: Docker Compose</li></ul><h2 id="_10-running-locally" tabindex="-1">10. Running Locally <a class="header-anchor" href="#_10-running-locally" aria-label="Permalink to &quot;10. Running Locally&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gateway</span></span></code></pre></div><p>실제 Secret, Database URL과 Upstream 주소는 실행 환경에서 주입합니다. 공개 저장소의 예시 값은 운영 환경에 사용하지 않습니다.</p><h2 id="_11-current-limitations" tabindex="-1">11. Current Limitations <a class="header-anchor" href="#_11-current-limitations" aria-label="Permalink to &quot;11. Current Limitations&quot;">​</a></h2><ul><li>Rate Limit 상태는 단일 프로세스 메모리에 있으므로 다중 Replica의 전역 Quota가 아닙니다.</li><li>Prompt Injection 방어는 Pattern과 정책 중심이며 의미론적 우회를 완전히 차단한다고 주장하지 않습니다.</li><li>현재 공개 Edge에서 온프레미스까지 안정적인 HTTPS Tunnel이 완료돼야 외부 Live Demo를 상시 제공할 수 있습니다.</li><li>공개 Demo는 운영 SLA를 제공하는 제품 API가 아니라 제한된 아키텍처 검증 환경입니다.</li></ul><h2 id="_12-next-steps" tabindex="-1">12. Next Steps <a class="header-anchor" href="#_12-next-steps" aria-label="Permalink to &quot;12. Next Steps&quot;">​</a></h2><ul><li>Cloudflare Tunnel 또는 동등한 Outbound-only HTTPS Ingress 적용</li><li>Redis 기반 분산 Rate Limit과 일일 Project Budget 추가</li><li>Project별 요청·Token·오류 SLO Recording Rule 구성</li><li>자동 Key Rotation과 긴급 폐기 Runbook 검증</li></ul>`,17))])}const C=d(p,[["render",A]]);export{B as __pageData,C as default};
